using UnityEngine;

/// <summary>
/// Objectivo cumprido ao recolher pelo menos "amount" unidades de "item"
/// DURANTE o desafio (a partir da quantidade que o jogador já tinha ao
/// iniciar — itens já possuídos não contam, e perder/usar o item depois de o
/// objectivo estar cumprido não o "descumpre"). Pensado para "Coleta
/// Cronometrada" usando os mesmos pickups/ItemData já existentes no mundo, sem
/// precisar de configurar variáveis/contadores à parte.
///
/// Mostra "recolhidos/amount" no HUD (Tarefa #12).
/// </summary>
[System.Serializable]
public class Objective_ItemCollected : ChallengeObjective
{
    [Tooltip("Item a recolher (ver ItemData).")]
    public ItemData item;

    [Tooltip("Quantidade a recolher DURANTE o desafio (além da que o jogador já possuía ao iniciar).")]
    [Min(1)] public int amount = 1;

    [System.NonSerialized] private int baselineQuantity;

    public override void ResetState()
    {
        baselineQuantity = (PlayerProgress.Instance != null && item != null) ? PlayerProgress.Instance.GetItemQuantity(item) : 0;
    }

    private int CollectedSinceStart()
    {
        if (item == null || PlayerProgress.Instance == null) return 0;
        return Mathf.Max(0, PlayerProgress.Instance.GetItemQuantity(item) - baselineQuantity);
    }

    public override bool IsComplete() => CollectedSinceStart() >= amount;

    public override int CurrentProgress() => Mathf.Min(CollectedSinceStart(), amount);

    public override int TargetProgress() => amount;
}

/// <summary>
/// Objectivo cumprido quando o cronómetro do desafio (ChallengeManager.ElapsedSeconds)
/// atinge "targetSeconds" — base de desafios de "Sobrevivência" (sobreviver X
/// segundos sem ser derrotado; combinar com FailCondition_PlayerDefeated e/ou
/// FailCondition_PlayerDamaged para definir o que conta como "falhar").
///
/// Mostra "decorridos/targetSeconds" (segundos, arredondados) no HUD (Tarefa #12).
/// </summary>
[System.Serializable]
public class Objective_SurviveTime : ChallengeObjective
{
    [Tooltip("Segundos que o desafio tem de permanecer activo para este objectivo estar cumprido.")]
    [Min(0f)] public float targetSeconds = 30f;

    public override bool IsComplete() =>
        ChallengeManager.Instance != null && ChallengeManager.Instance.ElapsedSeconds >= targetSeconds;

    public override int CurrentProgress() =>
        ChallengeManager.Instance != null ? Mathf.FloorToInt(Mathf.Min(ChallengeManager.Instance.ElapsedSeconds, targetSeconds)) : 0;

    public override int TargetProgress() => Mathf.CeilToInt(targetSeconds);
}

/// <summary>
/// Objectivo cumprido ao recolher <see cref="amount"/> Sementes durante a Provação
/// de Gaia. Conta pickups de tipo <see cref="PickupType.Semente"/> recolhidos
/// depois de o desafio ter iniciado (via <c>PlayerProgress.PickupCollected</c>).
///
/// Para "coleta todas as sementes da área", configurar <see cref="amount"/> com o
/// número total de Sementes existentes na zona do desafio.
///
/// Mostra "recolhidas/amount" no HUD.
/// </summary>
[System.Serializable]
public class Objective_SeedsCollected : ChallengeObjective
{
    [Tooltip("Sementes a recolher durante a Provação (além das que o jogador já tinha). Para 'recolhe todas', usar o total de sementes da área.")]
    [Min(1)] public int amount = 1;

    [System.NonSerialized] private int count;

    public override void ResetState()
    {
        count = 0;
        if (PlayerProgress.Instance != null)
        {
            PlayerProgress.Instance.PickupCollected -= OnPickupCollected;
            PlayerProgress.Instance.PickupCollected += OnPickupCollected;
        }
    }

    private void OnPickupCollected(PickupType type, string _)
    {
        if (type == PickupType.Semente) count++;
    }

    public override bool IsComplete() => count >= amount;
    public override int CurrentProgress() => Mathf.Min(count, amount);
    public override int TargetProgress() => amount;
}

/// <summary>
/// Objectivo cumprido ao recolher o coleccionável com
/// <see cref="PickupBase.pickupId"/> == <see cref="targetPickupId"/> durante
/// a Provação de Gaia. Funciona com qualquer pickup registado via
/// <c>PlayerProgress.PickupCollected</c>: Runas de Gaia, Fragmentos Vitais,
/// Runas de Apolo, Melodias Selvagens, itens específicos, etc.
///
/// Objectivo binário — o HUD mostra apenas o texto e ✓/✗ (sem contador).
/// </summary>
[System.Serializable]
public class Objective_SpecificPickupCollected : ChallengeObjective
{
    [Tooltip("PickupBase.pickupId do coleccionável a recolher durante a Provação (ex: 'runa_floresta_03', 'runa_apolo_mundo1', 'melodia_floresta_01').")]
    public string targetPickupId;

    [System.NonSerialized] private bool collected;

    public override void ResetState()
    {
        // Se o pickup já tinha sido recolhido antes do desafio (anti-duplicação),
        // o objectivo começa cumprido (raro, mas cobre o edge-case).
        collected = PlayerProgress.Instance != null
            && !string.IsNullOrEmpty(targetPickupId)
            && PlayerProgress.Instance.HasCollectedPickup(targetPickupId);

        if (PlayerProgress.Instance != null)
        {
            PlayerProgress.Instance.PickupCollected -= OnPickupCollected;
            PlayerProgress.Instance.PickupCollected += OnPickupCollected;
        }
    }

    private void OnPickupCollected(PickupType _, string pickupId)
    {
        if (pickupId == targetPickupId) collected = true;
    }

    public override bool IsComplete() => collected;
    // Objectivo binário — TargetProgress -1 faz o HUD mostrar só displayText.
    public override int TargetProgress() => -1;
}
